"use client"

import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Menu, ArrowLeft } from "lucide-react"
import { useState } from "react"
import { ThemeToggle } from "@/components/theme-toggle"

export function SiteHeader() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)

  const navLinks = [
    { name: "Home", href: "/" },
    { name: "Services", href: "/services" },
    { name: "Case Studies", href: "/case-studies" },
    { name: "Strategy", href: "/strategy" },
    { name: "Proof", href: "/proof" },
    { name: "About", href: "/about" },
    { name: "Contact", href: "/contact" },
  ]

  return (
    <header className="sticky top-0 z-50 w-full border-b-2 border-[#00a3a3]/30 bg-transparent backdrop-blur-md">
      <nav className="container mx-auto flex h-20 items-center justify-between px-4">
        
        {/* Logo */}
        <Link href="/" className="flex items-center space-x-2 group">
          <span className="text-3xl font-black tracking-tight text-[#00a3a3] group-hover:scale-105 transition-transform">
            ELARION
          </span>
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden lg:flex items-center gap-8">
          {navLinks.map((link) => (
            <Link
              key={link.name}
              href={link.href}
              className="text-base font-bold text-foreground/80 transition-all duration-300 hover:text-[#00a3a3] hover:scale-110 relative group"
            >
              {link.name}
              <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-[#00a3a3] transition-all duration-300 group-hover:w-full" />
            </Link>
          ))}

          <ThemeToggle />

          <Button
            asChild
            className="bg-[#00a3a3] text-white hover:bg-[#00a3a3]/90 font-bold transition-all duration-300 hover:scale-105"
          >
            <Link href="/ai-agents">AI Agents</Link>
          </Button>
        </div>

        {/* Mobile Controls */}
        <div className="flex items-center gap-3 lg:hidden">
          <ThemeToggle />

          <button
            className="p-2 rounded-md transition-all duration-300 hover:bg-[#00a3a3]/10"
            onClick={() => setMobileMenuOpen(true)}
          >
            <Menu className="h-7 w-7 text-[#00a3a3]" />
          </button>
        </div>
      </nav>

      {/* MOBILE MENU (PURE CSS SLIDE) */}
      {mobileMenuOpen && (
        <>
          {/* Background Overlay */}
          <div
            className="fixed inset-0 bg-white dark:bg-black z-40 transition-all duration-500 ease-in-out"
            onClick={() => setMobileMenuOpen(false)}
          />

          {/* Sliding Menu Panel */}
          <div
            className={`
              fixed top-0 right-0 h-full w-full
              z-50 p-6 flex flex-col
              transition-all duration-500 ease-in-out
              ${mobileMenuOpen ? "translate-x-0" : "translate-x-full"}

              bg-white dark:bg-black
            `}
          >
            {/* Back Button */}
            <button
              className="self-start mb-6 p-2 rounded-md transition-all duration-300 hover:bg-[#00a3a3]/10"
              onClick={() => setMobileMenuOpen(false)}
            >
              <ArrowLeft className="h-6 w-6 text-[#00a3a3]" />
            </button>

            {/* Links */}
            <div className="bg-white w-full">

            <div className="flex flex-col gap-4 ">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  href={link.href}
                  className="text-lg font-bold text-foreground/80 hover:text-[#00a3a3] transition-colors"
                  onClick={() => setMobileMenuOpen(false)}
                >
                  {link.name}
                </Link>
              ))}
            </div>
            </div>


            {/* Bottom Section */}
            <div className="mt-auto pt-6">
              <Button
                asChild
                className="w-full bg-[#00a3a3] text-white font-bold"
              >
                <Link
                  href="/ai-agents"
                  onClick={() => setMobileMenuOpen(false)}
                >
                  AI Agents
                </Link>
              </Button>
            </div>
          </div>
        </>
      )}
    </header>
  )
}
